package com.antam.app.dto;

import com.fasterxml.jackson.annotation.JsonIgnore;
import jakarta.persistence.*;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.util.List;

/*
 * @description
 * @author: Duong Nguyen
 * @date: 9/25/2025
 * version: 1.0
 */
@Data
@NoArgsConstructor(force = true)
@AllArgsConstructor
@Builder

@Entity
@Table(name = "Thuoc")
public class ThuocDTO {

    @Id
    @Column(name = "MaThuoc")
    private final String maThuoc;
    @Column(name = "TenThuoc")
    private String TenThuoc;
    @Column(name = "HamLuong")
    private String hamLuong;
    @Column(name = "GiaBan")
    private double giaBan;
    @Column(name = "GiaGoc")
    private double giaGoc;
    @Column(name = "Thue")
    private float thue;
    @Column(columnDefinition = "BOOLEAN DEFAULT FALSE",name = "DeleteAt")
    private boolean deleteAt;

    @ManyToOne
    @JoinColumn(name = "DangDieuChe")
    private DangDieuCheDTO dangDieuCheDTO;

    @ManyToOne
    @JoinColumn(name = "MaDVTCoso")
    private DonViTinhDTO maDVTCoSo;

    @ManyToOne
    @JoinColumn(name = "MaKe")
    private KeDTO maKeDTO;

    @OneToMany(mappedBy = "maThuoc")
    @JsonIgnore
    private List<LoThuocDTO> loThuocList;

    public ThuocDTO(String maThuoc) {
        this.maThuoc = maThuoc;
        this.TenThuoc = "";
        this.hamLuong = "";
        this.giaBan = 0;
        this.giaGoc = 0;
        this.thue = 0;
        this.deleteAt = false;
        this.dangDieuCheDTO = new DangDieuCheDTO();
        this.maDVTCoSo = new DonViTinhDTO();
        this.maKeDTO = new KeDTO();
    }

    public ThuocDTO(String maThuoc, String tenThuoc, String hamLuong, Double giaBan, Double giaGoc, float v, boolean b, DangDieuCheDTO dangDieuCheDTO, DonViTinhDTO donViCoSo, KeDTO keDTO) {
        this.maThuoc = maThuoc;
        this.TenThuoc = tenThuoc;
        this.hamLuong = hamLuong;
        this.giaBan = giaBan;
        this.giaGoc = giaGoc;
        this.thue = v;
        this.deleteAt = b;
        this.dangDieuCheDTO = dangDieuCheDTO;
        this.maDVTCoSo = donViCoSo;
        this.maKeDTO = keDTO;
    }
}

